  35: { type: "property", card: hevronElonMamrei },
  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};

// --- Build 44 board positions ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Modal Component ---
function CardModal({ card, onClose, mode, currentPlayer, updatePlayer }) {
  if (!card) return null;

  const isProperty = mode === "property";

  const handleBuyProperty = () => {
    if (currentPlayer.money < card.price) {
      alert("Not enough money to buy this property!");
      return;
    }
    updatePlayer({ ...currentPlayer, money: currentPlayer.money - card.price });
    card.ownerIndex = currentPlayer.index;
    alert(`${currentPlayer.name} bought ${card.name} for $${card.price}`);
    onClose();
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name}</h2>
        {isProperty && (
          <>
            <div style={{ height: 20, backgroundColor: card.colorGroup, marginBottom: 10, borderRadius: 4 }}></div>
            <p>Price: ${card.price}</p>
            <p>Rent: ${card.rent.base}</p>
            <p>Rent with 1 House: ${card.rent.house1}</p>
            <p>Rent with 2 Houses: ${card.rent.house2}</p>
            <p>Rent with 3 Houses: ${card.rent.house3}</p>
            <p>Rent with Hotel: ${card.rent.hotel}</p>
            <p>House Cost: ${card.buildCost.house}</p>
            <p>Hotel Cost: ${card.buildCost.hotel}</p>
            <p>Owner: {card.ownerIndex !== null ? `Player ${card.ownerIndex + 1}` : "None"}</p>
            <p>Your Money: ${currentPlayer.money}</p>
            {card.description && <p>{card.description}</p>}
            <button style={{ ...modalStyles.button, backgroundColor: "green" }} onClick={handleBuyProperty}>Buy Property</button>
            <button style={modalStyles.button} onClick={onClose}>Close</button>
          </>
        )}
      </div>
    </div>
  );
}

const modalStyles = {
  overlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000 },
  modal: { backgroundColor: "#fff", padding: 30, borderRadius: 12, minWidth: 300, maxWidth: "90%", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.3)" },
  button: { margin: "8px 5px", padding: "8px 15px", borderRadius: 6, border: "none", backgroundColor: "#007bff", color: "#fff", fontSize: 14, cursor: "pointer" },
};


// --- Main App Component ---
function App() {
  const [players, setPlayers] = useState([
    { index: 0, name: "Player 1", position: 0, money: 1500 },
    { index: 1, name: "Player 2", position: 0, money: 1500 },
  ]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [diceRoll, setDiceRoll] = useState(null);
  const [modalCard, setModalCard] = useState(null);
  const [showPropertyPanel, setShowPropertyPanel] = useState(false);

  const currentPlayer = players[currentPlayerIndex];

  const handleRollDice = (value) => {
    setDiceRoll(value);
    movePlayer(value);
  };

  const movePlayer = (steps) => {
    const newPlayers = [...players];
    let newPosition = (currentPlayer.position + steps) % defaultBoardPositions.length;
    newPlayers[currentPlayerIndex].position = newPosition;
    setPlayers(newPlayers);

    const landedEvent = boardEvents[newPosition];
    if (landedEvent && landedEvent.type === "property") {
      setModalCard(landedEvent.card);
    }

    setCurrentPlayerIndex((currentPlayerIndex + 1) % players.length);
  };

  const updatePlayer = (updatedPlayer) => {
    const newPlayers = [...players];
    newPlayers[updatedPlayer.index] = updatedPlayer;
    setPlayers(newPlayers);
  };

  const handlePayRent = (amount, property) => {
    if (property.ownerIndex === null) {
      alert("This property has no owner.");
      return;
    }
    if (property.ownerIndex === currentPlayer.index) {
      alert("You own this property!");
      return;
    }

    const newPlayers = [...players];
    if (currentPlayer.money < amount) {
      alert("Not enough money to pay rent!");
      return;
    }

    newPlayers[currentPlayer.index].money -= amount;
    newPlayers[property.ownerIndex].money += amount;
    setPlayers(newPlayers);
    alert(`${currentPlayer.name} paid $${amount} rent to Player ${property.ownerIndex + 1}`);
  };

  const togglePropertyPanel = () => setShowPropertyPanel(!showPropertyPanel);

  const getPlayerProperties = (playerIndex) => {
    return Object.values(boardEvents)
      .filter(ev => ev.card && ev.card.ownerIndex === playerIndex)
      .map(ev => ev.card);
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", marginTop: 20 }}>
      <h1>Torahpoly Game</h1>

      {/* Board */}
      <div style={{ position: "relative" }}>
        <img src={boardImage} alt="Board" style={{ width: referenceSize, height: referenceSize }} />
        {players.map(player => {
          const pos = defaultBoardPositions[player.position];
          return (
            <div key={player.index} style={{ position: "absolute", left: pos.x, top: pos.y, width: 30, height: 30, borderRadius: "50%", backgroundColor: player.index === 0 ? "red" : "blue", textAlign: "center", lineHeight: "30px", color: "white" }}>
              {player.index + 1}
            </div>
          );
        })}
      </div>

      {/* Dice */}
      <div style={{ margin: 20 }}>
        <Dice size={80} onRoll={handleRollDice} />
        {diceRoll && <p>Last Roll: {diceRoll}</p>}
      </div>

      {/* Show Property Panel */}
      <button style={{ margin: 10, padding: "8px 15px" }} onClick={togglePropertyPanel}>
        {showPropertyPanel ? "Hide My Properties" : "Show My Properties"}
      </button>

      {showPropertyPanel && (
        <div style={{ border: "1px solid #333", padding: 10, marginTop: 10, borderRadius: 8, backgroundColor: "#f9f9f9" }}>
          <h3>{currentPlayer.name}'s Properties:</h3>
          {getPlayerProperties(currentPlayer.index).length === 0 && <p>None</p>}
          {getPlayerProperties(currentPlayer.index).map((prop, idx) => (
            <div key={idx} style={{ marginBottom: 5 }}>
              <strong>{prop.name}</strong> - Houses: {prop.houses} - Hotel: {prop.hotel ? "Yes" : "No"} - Rent: ${prop.rent.base}
              <button style={{ marginLeft: 10 }} onClick={() => handlePayRent(prop.rent.base, prop)}>Pay Rent</button>
            </div>
          ))}
        </div>
      )}

      {/* Modal */}
      {modalCard && (
        <CardModal card={modalCard} onClose={() => setModalCard(null)} mode="property" currentPlayer={currentPlayer} updatePlayer={updatePlayer} />
      )}
    </div>
  );
}

export default App;
